import { Link, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import './Navbar.css';

export default function Navbar() {
  const { pathname } = useLocation();
  const { admin, logout } = useAuth();

  const links = [
    { to: '/', label: 'Home' },
    { to: '/videos', label: 'Videos' },
    { to: '/blogs', label: 'Blogs' },
  ];

  return (
    <nav className="navbar">
      <div className="navbar-inner">
        <Link to="/" className="navbar-brand">
          <span className="brand-icon">VD</span>
          <span className="brand-text">Very Direct</span>
        </Link>

        <div className="navbar-links">
          {links.map(({ to, label }) => (
            <Link
              key={to}
              to={to}
              className={`nav-link ${pathname === to ? 'active' : ''}`}
            >
              {label}
            </Link>
          ))}
        </div>

        <div className="navbar-actions">
          {admin ? (
            <>
              <Link to="/admin" className="nav-admin-btn">
                Dashboard
              </Link>
              <button type="button" className="nav-logout-btn" onClick={logout}>
                Logout
              </button>
            </>
          ) : (
            <Link to="/admin/login" className="nav-admin-btn">
              Admin
            </Link>
          )}
        </div>
      </div>
    </nav>
  );
}
